const sessionData = $('Upsert Sessão').item.json[0];
const historico = $input.all().map(i => i.json);
const chatInput = $('Chat Trigger').item.json.chatInput ?? '';

const messages = historico.map(msg => ({
  role: msg.role,
  content: msg.content
}));

return {
  session_id: sessionData.id,
  messages: messages,
  chatInput: chatInput
};
